import{_ as s,c as a,o as n,ae as r}from"./chunks/framework.Cd-3tpCq.js";const h=JSON.parse('{"title":"🏛️ Drupal - Architecture des fichiers","description":"","frontmatter":{},"headers":[],"relativePath":"drupal-project/installation/architecture.md","filePath":"drupal-project/installation/architecture.md"}'),o={name:"drupal-project/installation/architecture.md"};function t(i,e,l,p,c,u){return n(),a("div",null,e[0]||(e[0]=[r(`<h1 id="🏛️-drupal-architecture-des-fichiers" tabindex="-1">🏛️ Drupal - Architecture des fichiers <a class="header-anchor" href="#🏛️-drupal-architecture-des-fichiers" aria-label="Permalink to &quot;🏛️ Drupal - Architecture des fichiers&quot;">​</a></h1><p>Notre site <strong>Drupal</strong> est installé et initialisé.</p><p>Notre projet a maintenant l&#39;architecture suivante :</p><div class="language- vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang"></span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.</span></span>
<span class="line"><span>├── .ddev/</span></span>
<span class="line"><span>├── recipes/</span></span>
<span class="line"><span>├── vendor/</span></span>
<span class="line"><span>├── web/</span></span>
<span class="line"><span>│   ├── core</span></span>
<span class="line"><span>│   ├── modules</span></span>
<span class="line"><span>│   ├── profiles</span></span>
<span class="line"><span>│   ├── sites</span></span>
<span class="line"><span>│   └── themes</span></span>
<span class="line"><span>├── composer.json</span></span>
<span class="line"><span>└── composer.lock</span></span></code></pre></div><p>Faisons un rapide tour d&#39;horizon des nouveaux dossiers et fichiers.</p><h2 id="recipes" tabindex="-1">recipes/ <a class="header-anchor" href="#recipes" aria-label="Permalink to &quot;recipes/&quot;">​</a></h2><p>Les <strong>recipes</strong> automatisent l’installation et la configuration des modules en créant des scripts capables d’installer des modules et des thèmes, et de configurer un site <strong>Drupal</strong> déjà existant.</p><p>Nous aborderons les <strong>recipes</strong> dans un prochain chapitre.</p><h2 id="vendor" tabindex="-1">vendor/ <a class="header-anchor" href="#vendor" aria-label="Permalink to &quot;vendor/&quot;">​</a></h2><p>Le dossier <em>vendor</em> contient les dépendances de notre projet <strong>Drupal</strong>.</p><h2 id="web" tabindex="-1">web/ <a class="header-anchor" href="#web" aria-label="Permalink to &quot;web/&quot;">​</a></h2><p>C&#39;est le dossier racine de notre site <strong>Drupal</strong>. C&#39;est dans ce dossier que se trouvent les fichiers principaux du site. C&#39;est également dans ce dossier que nous allons principalement développer.</p><p>D&#39;ailleurs, souvenez-vous, lors de l&#39;installation du projete avec <strong>DDEV</strong>, nous avons précisé <code>--docroot=web</code>.</p><h3 id="web-core" tabindex="-1">web/core/ <a class="header-anchor" href="#web-core" aria-label="Permalink to &quot;web/core/&quot;">​</a></h3><p>Ce dossier contient les fichiers principaux du cœur de <strong>Drupal</strong>. Ce qui est un peu surprenant d&#39;ailleurs, on pourrait s&#39;attendre à ce que tout se trouve dans le dossier <em>vendor</em>.</p><h3 id="web-modules" tabindex="-1">web/modules/ <a class="header-anchor" href="#web-modules" aria-label="Permalink to &quot;web/modules/&quot;">​</a></h3><p>Comme son nom l&#39;indique, ce dossier contient les modules <strong>Drupal</strong>, qu&#39;ils soient contribués, c&#39;est-à-dire installés via <strong>Composer</strong>, ou que nous développerons nous même.</p><h3 id="web-profiles" tabindex="-1">web/profiles/ <a class="header-anchor" href="#web-profiles" aria-label="Permalink to &quot;web/profiles/&quot;">​</a></h3><p>Le dossier <em>web/profiles</em> contient les profils d&#39;installation de Drupal. Ce sont des ensembles de configurations, modules et thèmes qui définissent comment un site Drupal sera configuré lors de son initialisation.</p><p>Avec l&#39;apparition de la version 10.3 de <strong>Drupal</strong>, les profils d&#39;installation vont peu à peu disparaître. Raison pour laquelle nous n&#39;aborderons pas les profils d&#39;installation dans cette formation.</p><h3 id="web-themes" tabindex="-1">web/themes/ <a class="header-anchor" href="#web-themes" aria-label="Permalink to &quot;web/themes/&quot;">​</a></h3><p>Ce dossier contient les thèmes graphiques de <strong>Drupal</strong>. Tout comme pour le dossier <em>web/modules</em>, les thèmes peuvent être contribués ou créés de toutes pièces.</p><h3 id="web-sites" tabindex="-1">web/sites/ <a class="header-anchor" href="#web-sites" aria-label="Permalink to &quot;web/sites/&quot;">​</a></h3><p>Ce dossier contient les fichiers de configuration du site <strong>Drupal</strong>.</p><h2 id="composer-json-et-composer-lock" tabindex="-1">composer.json et composer.lock <a class="header-anchor" href="#composer-json-et-composer-lock" aria-label="Permalink to &quot;composer.json et composer.lock&quot;">​</a></h2><p>Ces fichiers sont générés automatiquement par <strong>Composer</strong> lors de l&#39;installation des dépendances du projet.</p><h2 id="une-architecture-simple" tabindex="-1">Une architecture simple <a class="header-anchor" href="#une-architecture-simple" aria-label="Permalink to &quot;Une architecture simple&quot;">​</a></h2><p>Comme vous pouvez le voir, l&#39;architecture d&#39;un projet <strong>Drupal</strong> est sobre et bien structurée. Nous allons principalement travailler dans le dossier <em>web/modules</em> et <em>web/themes</em>.</p><div class="info custom-block"><p class="custom-block-title">Gérer le versionnage des fichiers</p><p>Comme vu lors d&#39;un précédent chapitre, nous avons initialisé <strong>Git</strong> sur notre projet. Faisons un point sur les fichiers que nous souhaitons versionner avec le fichier <a href="/drupal-project/installation/gitignore.html"><em>.gitignore</em></a>.</p></div>`,29)]))}const m=s(o,[["render",t]]);export{h as __pageData,m as default};
